custom_css.value:
html[data-theme="dark"] { --color-bg:#ffffff; --color-surface:#F9F5F5; --color-text:#1f2933; --color-text-muted:#64748b; --color-border:#d7dce3; }
body, .page { background:#ffffff; color:#1f2933; }
.page .nav { background:#fff; border-bottom:0; padding:.5rem 0 0; box-shadow:0 1px 0 rgba(31,41,51,.12); }
.nav > .container { flex-wrap:wrap; align-items:center; gap:.6rem 1rem; }
.brand-header--icon .brand-icon { width:auto; height:4.2rem; max-width:9rem; object-fit:contain; }
.brand-text { font-weight:800; color:#1f2933; letter-spacing:0; font-size:1.15rem; }
.nav .section-site-search { order:2; padding:0; margin-left:auto; flex:0 1 18rem; max-width:18rem; }
.nav .section-site-search > .container { max-width:none; padding:0; margin:0; }
.nav .site-search { max-width:18rem; margin-left:auto; }
.nav .site-search__form { height:2.1rem; display:flex; border:1px solid #d7dce3; border-radius:.2rem; overflow:hidden; background:#fff; }
.nav .site-search__input { border:0; min-width:0; width:100%; max-width:none; padding:0 .65rem; }
.nav .site-search__submit { border:0; border-radius:0; background:#F38C1C; color:#172033; font-weight:700; padding:0 .8rem; }
.nav .block-social-links { order:3; padding:0; --social-link-size:1.8rem; --social-link-icon-size:1rem; --social-link-radius:.2rem; --social-link-bg:#3F88E8; --social-link-color:#fff; --social-link-border:transparent; }
.nav .block-social-links__list { gap:.35rem; }
.nav-links { order:4; flex-basis:100%; display:flex; flex-wrap:wrap; gap:0; background:#3F88E8; padding:0 .45rem; }
.nav-link { color:#fff; border-radius:0; padding:.62rem .75rem; font-weight:700; font-size:.88rem; }
.nav-link:hover, .nav-link.active { background:#F38C1C; color:#172033; }
.nav-user { order:5; margin-left:auto; }
.section-slideshow { padding:1.25rem 0 0; }
.section-slideshow .container { max-width:76rem; }
.block-slideshow { border-radius:.25rem; box-shadow:0 12px 28px rgba(23,32,51,.14); }
#sections > section:first-child { padding:1.25rem 0 0; }
.section-events-list { background:#F9F5F5; margin-top:1.5rem; padding:2rem 0; }
.bmwcc-content { max-width:76rem; margin:0 auto; font-size:1rem; line-height:1.65; }
.bmwcc-content h1 { color:#3F88E8; font-size:clamp(1.55rem,3vw,2.35rem); line-height:1.15; margin:1rem 0 .85rem; }
.bmwcc-content h2, .bmwcc-content h3 { color:#172033; margin:1rem 0 .55rem; }
.bmwcc-content table { width:100%; border-collapse:collapse; }
.bmwcc-content td { vertical-align:top; padding:.35rem; }
.bmwcc-content picture { display:inline-block; max-width:100%; }
.bmwcc-content img { max-width:100%; height:auto; border-radius:.2rem; }
.bmwcc-content a { color:#2467bf; font-weight:700; }
.bmwcc-home-intro { padding-top:1.25rem; }
.bmwcc-home-panels { display:grid; grid-template-columns:minmax(0,1fr); gap:1.25rem; margin:1.5rem 0; }
.bmwcc-home-panels > div { border-left:4px solid #F38C1C; background:#F9F5F5; padding:1rem 1.15rem; }
.bmwcc-home-footer { display:grid; grid-template-columns:repeat(3,minmax(0,1fr)); gap:1.25rem; margin:2rem auto 0; }
.bmwcc-home-footer > div { border-top:3px solid #F38C1C; padding-top:.85rem; }
.bmwcc-social-link-list, .bmwcc-footer-social { display:flex; flex-wrap:wrap; gap:.5rem; margin-top:.75rem; }
.bmwcc-social-link-list a, .bmwcc-footer-social a { display:inline-flex; align-items:center; min-height:2rem; padding:.35rem .65rem; border-radius:.2rem; background:#3F88E8; color:#fff; text-decoration:none; font-weight:700; }
.bmwcc-contact-social { margin-top:1.25rem; }
.footer { background:#172033; color:#fff; border-top:0; padding:2rem 0 1rem; }
.footer a { color:#fff; }
.footer > .container { display:grid; grid-template-columns:minmax(0,2fr) minmax(11rem,1fr); gap:1.5rem; align-items:start; }
.footer .section { padding:0; opacity:1; }
.footer .section > .container { max-width:none; padding:0; margin:0; }
.footer-links { display:grid; grid-template-columns:repeat(3,minmax(0,1fr)); gap:1.25rem; }
.footer-links-col h4 { color:#F38C1C; }
.footer-links ul { list-style:none; padding:0; margin:0; }
.footer-links li { margin:.35rem 0; }
@media (max-width: 820px) {
  .brand-header--icon .brand-icon { height:3.2rem; }
  .nav .section-site-search, .nav .block-social-links { width:100%; margin-left:0; order:3; }
  .nav .site-search, .nav .site-search__form { width:100%; }
  .nav .site-search__input { min-width:0; width:100%; max-width:none; }
  .nav-links { order:5; display:none; flex-direction:column; background:rgba(255,255,255,.96); padding:.5rem 1.5rem; box-shadow:0 12px 28px rgba(23,32,51,.14); }
  .nav-links.open { display:flex; }
  .nav-link { color:#1f2933; }
  .nav-link.active { background:#F38C1C; color:#172033; }
  .bmwcc-home-footer { grid-template-columns:1fr; }
  .footer > .container { grid-template-columns:1fr; }
  .footer-links { grid-template-columns:repeat(3,minmax(0,1fr)); text-align:left; }
}
@media (max-width: 520px) {
  .footer-links { grid-template-columns:1fr; }
}
